import { useState, useEffect, useRef } from 'react';
import { SlideData, INITIAL_SLIDE, createNewSlide, SlideLayout, ThemeId, TypographyId, THEMES, TYPOGRAPHY_STYLES } from '../types';
import { supabase } from '../services/supabaseClient';

export const usePresentation = () => {
    const [slides, setSlides] = useState<SlideData[]>([INITIAL_SLIDE]);
    const [currentSlideIndex, setCurrentSlideIndex] = useState(0);
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
    const [isLoaded, setIsLoaded] = useState(false);
    const isFirstLoad = useRef(true);

    const currentSlide = slides[currentSlideIndex] || slides[0];

    // --- Persistence Logic ---

    // Load
    useEffect(() => {
        const loadData = async () => {
            try {
                const { data, error } = await supabase
                    .from('presentations')
                    .select('slides')
                    .eq('id', 1)
                    .single();

                if (error) {
                    console.log("Supabase load info:", error.message);
                } else if (data && data.slides && Array.isArray(data.slides) && data.slides.length > 0) {
                    setSlides(data.slides);
                }
            } catch (e) {
                console.error("Failed to fetch from supabase:", e);
            } finally {
                setIsLoaded(true);
                setTimeout(() => { isFirstLoad.current = false; }, 500);
            }
        };
        loadData();
    }, []);

    // Save Helper
    const saveToCloud = async (slidesToSave: SlideData[]) => {
        setSaveStatus('saving');
        try {
            const { error } = await supabase.from('presentations').upsert({ id: 1, slides: slidesToSave });
            if (error) throw error;
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 2000);
        } catch (error: any) {
            console.error("Failed to save to Supabase:", error);
            setSaveStatus('error');
        }
    };

    // Auto-Save
    useEffect(() => {
        if (!isLoaded || isFirstLoad.current) return;
        const timeoutId = setTimeout(() => {
            saveToCloud(slides);
        }, 2000);
        return () => clearTimeout(timeoutId);
    }, [slides, isLoaded]);


    // --- Slide Operations ---

    const handleUpdateSlide = (updatedSlide: SlideData) => {
        // Universal Changes logic from original App.tsx
        const oldSlide = slides[currentSlideIndex];
        let newSlides = slides.map((s, index) => index === currentSlideIndex ? updatedSlide : s);

        // Apply Global changes if these specific fields changed
        if (oldSlide.theme !== updatedSlide.theme) {
            newSlides = newSlides.map(s => ({ ...s, theme: updatedSlide.theme }));
        }
        if (oldSlide.typography !== updatedSlide.typography) {
            newSlides = newSlides.map(s => ({ ...s, typography: updatedSlide.typography }));
        }
        if (oldSlide.textTransition !== updatedSlide.textTransition) {
            newSlides = newSlides.map(s => ({ ...s, textTransition: updatedSlide.textTransition }));
        }
        if (oldSlide.imageTransition !== updatedSlide.imageTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageTransition: updatedSlide.imageTransition }));
        }
        if (oldSlide.textOutroTransition !== updatedSlide.textOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, textOutroTransition: updatedSlide.textOutroTransition }));
        }
        if (oldSlide.imageOutroTransition !== updatedSlide.imageOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageOutroTransition: updatedSlide.imageOutroTransition }));
        }

        setSlides(newSlides);
    };

    const handleAddSlide = (layout: SlideLayout = 'text-image') => {
        const newSlide = createNewSlide(layout);
        const refSlide = slides[currentSlideIndex] || slides[0];
        // Inherit styles
        newSlide.theme = refSlide.theme || 'cyber-future';
        newSlide.typography = refSlide.typography || 'modern-sans';
        newSlide.textTransition = refSlide.textTransition || 'slide-up';
        newSlide.imageTransition = refSlide.imageTransition || 'zoom-in';
        newSlide.textOutroTransition = refSlide.textOutroTransition || 'none';
        newSlide.imageOutroTransition = refSlide.imageOutroTransition || 'none';

        // Auto-increment badge step
        const lastSlide = slides[slides.length - 1];
        if (lastSlide && lastSlide.badge.startsWith('Step ')) {
            const num = parseInt(lastSlide.badge.split(' ')[1]);
            if (!isNaN(num)) newSlide.badge = `Step ${num + 1}`;
        }

        setSlides([...slides, newSlide]);
        setCurrentSlideIndex(slides.length);
    };

    const handleDuplicateSlide = (index: number) => {
        const slide = slides[index];
        if (!slide) return;
        const newSlide = { ...slide, id: Date.now().toString() };
        const newSlides = [...slides];
        newSlides.splice(index + 1, 0, newSlide);
        setSlides(newSlides);
        setCurrentSlideIndex(index + 1);
    };

    const handleDeleteSlide = (index: number) => {
        if (slides.length <= 1) return;
        const newSlides = slides.filter((_, i) => i !== index);
        setSlides(newSlides);
        if (currentSlideIndex >= index && currentSlideIndex > 0) {
            setCurrentSlideIndex(currentSlideIndex - 1);
        } else if (currentSlideIndex >= newSlides.length) {
            setCurrentSlideIndex(newSlides.length - 1);
        }
    };

    const handleReorderSlides = (from: number, to: number) => {
        if (from === to) return;
        const newSlides = [...slides];
        const [moved] = newSlides.splice(from, 1);
        newSlides.splice(to, 0, moved);
        setSlides(newSlides);

        if (currentSlideIndex === from) setCurrentSlideIndex(to);
        else if (from < currentSlideIndex && to >= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex - 1);
        else if (from > currentSlideIndex && to <= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex + 1);
    };

    const applyTheme = (id: ThemeId) => setSlides(slides.map(s => ({ ...s, theme: id })));
    const applyTypography = (id: TypographyId) => setSlides(slides.map(s => ({ ...s, typography: id })));

    const randomizeLook = () => {
        const t = THEMES[Math.floor(Math.random() * THEMES.length)];
        const f = TYPOGRAPHY_STYLES[Math.floor(Math.random() * TYPOGRAPHY_STYLES.length)];
        setSlides(slides.map(s => ({ ...s, theme: t.id, typography: f.id })));
    };

    // Project File Management
    const newProject = () => {
        if (window.confirm("Start new project? Unsaved changes will be lost.")) {
            setSlides([INITIAL_SLIDE]);
            setCurrentSlideIndex(0);
            setTimeout(() => saveToCloud([INITIAL_SLIDE]), 500);
        }
    };

    const loadProject = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target?.result as string);
                if (Array.isArray(json) && json.length > 0 && json[0].id) {
                    setSlides(json as SlideData[]);
                    setCurrentSlideIndex(0);
                    setTimeout(() => saveToCloud(json), 500);
                } else {
                    alert("Invalid project file.");
                }
            } catch (err) {
                console.error(err);
                alert("Failed to parse project file.");
            }
        };
        reader.readAsText(file);
    };

    const saveProject = () => {
        try {
            const blob = new Blob([JSON.stringify(slides, null, 2)], { type: "application/json" });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `slideforge-${new Date().toISOString().slice(0, 10)}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch(e) { console.error(e); }
    };

    return {
        slides,
        currentSlideIndex,
        currentSlide,
        saveStatus,
        isLoaded,
        setSlides,
        setCurrentSlideIndex,
        updateSlide: handleUpdateSlide,
        addSlide: handleAddSlide,
        duplicateSlide: handleDuplicateSlide,
        deleteSlide: handleDeleteSlide,
        reorderSlide: handleReorderSlides,
        manualSave: () => saveToCloud(slides),
        applyTheme,
        applyTypography,
        randomizeLook,
        newProject,
        loadProject,
        saveProject
    };
};

import { useState, useEffect } from 'react';

export const usePlayback = (duration: number = 5) => {
    const [isPlaying, setIsPlaying] = useState(false);
    const [progress, setProgress] = useState(0);

    // Reset progress when duration or slide changes (usually handled by parent resetting key, but we ensure defaults)
    useEffect(() => {
        setIsPlaying(false);
        // Start at 20% (approx 1s) for preview visibility
        const startSec = 1;
        const startProg = duration > 0 ? (startSec / duration) * 100 : 0;
        setProgress(Math.min(startProg, 100));
    }, [duration]);

    // Animation Loop
    useEffect(() => {
        let rafId: number;
        let lastTime: number | undefined;

        const animate = (time: number) => {
            if (lastTime !== undefined) {
                const delta = (time - lastTime) / 1000;
                setProgress(prev => {
                    const inc = (delta / duration) * 100;
                    const next = prev + inc;
                    if (next >= 100) {
                        setIsPlaying(false);
                        return 0;
                    }
                    return next;
                });
            }
            lastTime = time;
            if (isPlaying) rafId = requestAnimationFrame(animate);
        };

        if (isPlaying) rafId = requestAnimationFrame(animate);
        else lastTime = undefined;

        return () => { if (rafId) cancelAnimationFrame(rafId); };
    }, [isPlaying, duration]);

    return {
        isPlaying,
        progress,
        togglePlay: () => setIsPlaying(!isPlaying),
        scrub: (p: number) => {
            setIsPlaying(false);
            setProgress(p);
        }
    };
};

import { useState, useEffect, RefObject } from 'react';

export const useScale = (containerRef: RefObject<HTMLDivElement | null>) => {
    const [scale, setScale] = useState(0.5);

    useEffect(() => {
        const handleResize = () => {
            if (containerRef.current) {
                const { clientWidth, clientHeight } = containerRef.current;
                const targetW = 1920;
                const targetH = 1080;
                const padX = 80;
                const padY = 160;

                const availW = clientWidth - padX;
                const availH = clientHeight - padY;

                const scaleX = availW / targetW;
                const scaleY = availH / targetH;

                setScale(Math.min(scaleX, scaleY));
            }
        };

        window.addEventListener('resize', handleResize);
        handleResize();
        return () => window.removeEventListener('resize', handleResize);
    }, [containerRef]);

    return scale;
};

import { useState, useRef } from 'react';
import { SlideData, ExportJob } from '../types';
import * as Mp4Muxer from 'mp4-muxer';
import { toCanvas } from 'html-to-image';
import JSZip from 'jszip';

export const useExportManager = (
    slides: SlideData[], 
    currentSlide: SlideData,
    exportContainerRef: React.RefObject<HTMLDivElement | null>
) => {
    // UI State
    const [isExportModalOpen, setIsExportModalOpen] = useState(false);
    const [exportModalTab, setExportModalTab] = useState<'settings' | 'queue'>('settings');

    // Settings State (Local to manager)
    const [exportScope, setExportScope] = useState<'current' | 'all'>('current');
    const [exportQuality, setExportQuality] = useState<'720p' | '1080p' | '4k'>('1080p');
    const [exportBitrate, setExportBitrate] = useState<'low' | 'medium' | 'high'>('medium');
    const [exportFormat, setExportFormat] = useState<'mp4' | 'zip'>('mp4');
    const [exportImageFormat, setExportImageFormat] = useState<'jpeg' | 'png'>('jpeg');

    // Execution State
    const [exportQueue, setExportQueue] = useState<ExportJob[]>([]);
    const [isExporting, setIsExporting] = useState(false);
    const [exportProgressStatus, setExportProgressStatus] = useState(0);
    const [exportingSlide, setExportingSlide] = useState<SlideData | null>(null);
    const [exportRenderProgress, setExportRenderProgress] = useState(0);

    const openExportModal = (scope: 'current' | 'all') => {
        setExportScope(scope);
        setIsExportModalOpen(true);
        setExportModalTab('settings');
    };

    const queueExport = () => {
        const slidesSnapshot = exportScope === 'current' ? [currentSlide] : [...slides];
        const newJob: ExportJob = {
            id: Date.now().toString(),
            status: 'pending',
            createdAt: Date.now(),
            scope: exportScope,
            slides: JSON.parse(JSON.stringify(slidesSnapshot)),
            quality: exportQuality,
            bitrate: exportBitrate,
            format: exportFormat,
            imageFormat: exportImageFormat
        };
        setExportQueue([...exportQueue, newJob]);
        setExportModalTab('queue');
    };

    const processQueue = async () => {
        if (isExporting) return;
        const pending = exportQueue.filter(j => j.status === 'pending');
        if (pending.length === 0) return;

        for (const job of pending) {
            setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'processing' } : j));
            try {
                await executeExport(job);
                setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'completed' } : j));
            } catch (e) {
                console.error(e);
                setExportQueue(prev => prev.map(j => j.id === job.id ? { ...j, status: 'failed' } : j));
            }
            await new Promise(r => setTimeout(r, 1000));
        }
        setIsExporting(false);
        setExportingSlide(null);
        setExportProgressStatus(0);
    };

    const executeExport = async (job?: ExportJob) => {
        if (!job && isExporting) return;
        if (!exportContainerRef.current) return;

        setIsExporting(true);
        setExportProgressStatus(0);

        const cfgQuality = job ? job.quality : exportQuality;
        const cfgBitrate = job ? job.bitrate : exportBitrate;
        const cfgFormat = job ? job.format : exportFormat;
        const cfgScope = job ? job.scope : exportScope;
        const cfgSlides = job ? job.slides : (exportScope === 'current' ? [currentSlide] : slides);
        const cfgImageFormat = job ? job.imageFormat : exportImageFormat;

        const FPS = 30;
        let WIDTH = 1920;
        let HEIGHT = 1080;
        let bitRate = 5_000_000;

        if (cfgQuality === '720p') {
            WIDTH = 1280; HEIGHT = 720;
            bitRate = cfgBitrate === 'low' ? 1.5e6 : cfgBitrate === 'medium' ? 2.5e6 : 4e6;
        } else if (cfgQuality === '1080p') {
            WIDTH = 1920; HEIGHT = 1080;
            bitRate = cfgBitrate === 'low' ? 3e6 : cfgBitrate === 'medium' ? 5e6 : 8e6;
        } else if (cfgQuality === '4k') {
            WIDTH = 3840; HEIGHT = 2160;
            bitRate = cfgBitrate === 'low' ? 8e6 : cfgBitrate === 'medium' ? 12e6 : 20e6;
        }

        try {
            let muxer: any = null;
            let videoEncoder: VideoEncoder | null = null;
            let zip: JSZip | null = null;

            if (cfgFormat === 'mp4') {
                muxer = new Mp4Muxer.Muxer({
                    target: new Mp4Muxer.ArrayBufferTarget(),
                    video: { codec: 'avc', width: WIDTH, height: HEIGHT },
                    fastStart: 'in-memory',
                    firstTimestampBehavior: 'offset',
                });
                const codecStr = cfgQuality === '4k' ? 'avc1.640033' : 'avc1.4d002a';
                videoEncoder = new VideoEncoder({
                    output: (chunk, meta) => muxer.addVideoChunk(chunk, meta),
                    error: (e) => console.error(e)
                });
                videoEncoder.configure({ codec: codecStr, width: WIDTH, height: HEIGHT, bitrate: bitRate });
            } else {
                zip = new JSZip();
            }

            let totalExportFrames = 0;
            cfgSlides.forEach(s => totalExportFrames += Math.ceil((s.duration || 5) * FPS));
            let globalFrameCount = 0;

            for (const slide of cfgSlides) {
                setExportingSlide(slide);
                await new Promise(resolve => setTimeout(resolve, 250));

                const duration = slide.duration || 5;
                const frames = Math.ceil(duration * FPS);

                for (let i = 0; i < frames; i++) {
                    const prog = (i / (frames - 1)) * 100;
                    setExportRenderProgress(prog);
                    setExportProgressStatus(Math.round((globalFrameCount / totalExportFrames) * 100));
                    await new Promise(resolve => setTimeout(resolve, 0));

                    if (exportContainerRef.current) {
                        try {
                            const canvas = await toCanvas(exportContainerRef.current, {
                                width: WIDTH, height: HEIGHT, pixelRatio: 1, cacheBust: true,
                                style: { transform: 'none', transformOrigin: 'top left' },
                                fontEmbedCSS: '',
                            });

                            if (cfgFormat === 'mp4' && videoEncoder) {
                                const frame = new VideoFrame(canvas, { timestamp: (globalFrameCount * 1e6) / FPS, duration: 1e6 / FPS });
                                videoEncoder.encode(frame);
                                frame.close();
                            } else if (cfgFormat === 'zip' && zip) {
                                const mime = cfgImageFormat === 'jpeg' ? 'image/jpeg' : 'image/png';
                                const q = cfgImageFormat === 'jpeg' ? 0.9 : undefined;
                                const ext = cfgImageFormat === 'jpeg' ? 'jpg' : 'png';
                                const blob = await new Promise<Blob | null>(r => canvas.toBlob(r, mime, q));
                                if (blob) zip.file(`frame_${String(globalFrameCount).padStart(5,'0')}.${ext}`, blob);
                            }
                        } catch (err) { console.warn(err); }
                    }
                    globalFrameCount++;
                }
            }

            let blob: Blob;
            let filename: string;
            const baseName = cfgScope === 'current' && cfgSlides.length === 1 ? `slide-${cfgSlides[0].badge.replace(/\s+/g,'_')}` : `presentation`;

            if (cfgFormat === 'mp4' && videoEncoder && muxer) {
                await videoEncoder.flush();
                muxer.finalize();
                blob = new Blob([muxer.target.buffer], { type: 'video/mp4' });
                filename = `${baseName}_${cfgQuality}.mp4`;
            } else if (cfgFormat === 'zip' && zip) {
                blob = await zip.generateAsync({ type: "blob" });
                filename = `${baseName}_frames.zip`;
            } else { throw new Error("Invalid state"); }

            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url; a.download = filename;
            document.body.appendChild(a); a.click(); document.body.removeChild(a); URL.revokeObjectURL(url);

            if (!job) {
                setTimeout(() => { setIsExportModalOpen(false); setIsExporting(false); setExportProgressStatus(0); }, 1000);
            }
        } catch (e: any) {
            console.error("Export Failed", e);
            if (!job) alert(`Export failed: ${e.message}`);
            else throw e;
        } finally {
            if (!job) { setExportingSlide(null); setIsExporting(false); }
        }
    };

    return {
        // UI State
        isExportModalOpen, setIsExportModalOpen,
        exportModalTab, setExportModalTab,
        // Settings State setters
        setExportQuality, setExportBitrate, setExportFormat, setExportImageFormat,
        // Settings State getters
        exportScope, exportQuality, exportBitrate, exportFormat, exportImageFormat,
        // Queue & Status
        exportQueue, setExportQueue,
        isExporting,
        exportProgressStatus,
        exportingSlide,
        exportRenderProgress,
        // Actions
        openExportModal,
        queueExport,
        processQueue,
        executeExport, // Direct start
        deleteJob: (id: string) => setExportQueue(q => q.filter(j => j.id !== id))
    };
};

