export default LoadingScreen;

import React from 'react';
import SlideRenderer from './SlideRenderer';
import { SlideData } from '../types';

interface HiddenExportRendererProps {
    slide: SlideData | null;
    progress: number;
}

// Forward ref to allow App to access the div
const HiddenExportRenderer = React.forwardRef<HTMLDivElement, HiddenExportRendererProps>(({ slide, progress }, ref) => {
    if (!slide) return <div ref={ref} style={{ width: 1920, height: 1080 }} />;

    return (
        <div 
            style={{ 
                position: 'fixed', 
                top: -10000, 
                left: -10000, 
                width: 1920, 
                height: 1080,
                overflow: 'hidden',
                visibility: 'visible',
                zIndex: -1
            }}
        >
            <div ref={ref}>
                <SlideRenderer 
                    // Force remount on slide change for clean animation
                    key={`export-${slide.id}`}
                    data={slide} 
                    scale={1} 
                    progress={progress} 
                />
            </div>
        </div>
    );
});

export default HiddenExportRenderer;

import React, { useRef, useState, useEffect } from 'react';
import { LayoutTemplate, Cloud, Loader2, AlertCircle, Type, ChevronDown, Check, Shuffle, FolderOpen, FilePlus, Upload, FileDown, Download } from 'lucide-react';
import { SlideData, ThemeId, THEMES, TypographyId, TYPOGRAPHY_STYLES } from '../types';

interface TopBarProps {
    currentSlide: SlideData;
    saveStatus: 'idle' | 'saving' | 'saved' | 'error';
    isExporting: boolean;
    onApplyTheme: (id: ThemeId) => void;
    onApplyTypography: (id: TypographyId) => void;
    onRandomize: () => void;
    onManualSave: () => void;
    onNewProject: () => void;
    onLoadProject: (file: File) => void;
    onSaveProject: () => void;
    onOpenExport: (scope: 'current' | 'all') => void;
}

const TopBar: React.FC<TopBarProps> = ({
    currentSlide, saveStatus, isExporting,
    onApplyTheme, onApplyTypography, onRandomize, onManualSave,
    onNewProject, onLoadProject, onSaveProject, onOpenExport
}) => {
    const [isThemeOpen, setIsThemeOpen] = useState(false);
    const [isTypeOpen, setIsTypeOpen] = useState(false);
    const [isProjOpen, setIsProjOpen] = useState(false);
    const [isExpOpen, setIsExpOpen] = useState(false);

    const themeRef = useRef<HTMLDivElement>(null);
    const typeRef = useRef<HTMLDivElement>(null);
    const projRef = useRef<HTMLDivElement>(null);
    const expRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Click outside handler
    useEffect(() => {
        const handleClick = (e: MouseEvent) => {
            const target = e.target as Node;
            if (themeRef.current && !themeRef.current.contains(target)) setIsThemeOpen(false);
            if (typeRef.current && !typeRef.current.contains(target)) setIsTypeOpen(false);
            if (projRef.current && !projRef.current.contains(target)) setIsProjOpen(false);
            if (expRef.current && !expRef.current.contains(target)) setIsExpOpen(false);
        };
        document.addEventListener('mousedown', handleClick);
        return () => document.removeEventListener('mousedown', handleClick);
    }, []);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files?.[0]) {
            onLoadProject(e.target.files[0]);
            e.target.value = '';
        }
        setIsProjOpen(false);
    };

    return (
        <header className="h-16 border-b border-white/10 bg-[#0f0f0f] flex items-center justify-between px-6 shrink-0 z-50">
            <input type="file" accept=".json" ref={fileInputRef} onChange={handleFileChange} className="hidden" />

            {/* Left: Branding & Status */}
            <div className="flex items-center gap-3">
                <div className="w-8 h-8 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-lg flex items-center justify-center">
                    <LayoutTemplate size={18} className="text-white" />
                </div>
                <span className="font-bold text-lg tracking-tight">SlideForge</span>

                <div className="flex items-center justify-center gap-2 px-3 py-1 rounded-full bg-white/5 border border-white/10 text-xs font-medium w-[140px]">
                    {saveStatus === 'saving' && <><Loader2 size={12} className="animate-spin text-indigo-400" /><span className="text-indigo-300">Saving...</span></>}
                    {saveStatus === 'saved' && <><Cloud size={12} className="text-green-400" /><span className="text-green-300">Synced</span></>}
                    {saveStatus === 'error' && <><AlertCircle size={12} className="text-red-400" /><span className="text-red-300">Sync Error</span></>}
                    {saveStatus === 'idle' && <><Cloud size={12} className="text-gray-400" /><span className="text-gray-400">Cloud Active</span></>}
                </div>
            </div>

            {/* Center: Style Controls */}
            <div className="flex items-center gap-3">
                {/* Typography */}
                <div className="relative" ref={typeRef}>
                    <button onClick={() => setIsTypeOpen(!isTypeOpen)} className={`flex items-center gap-2 bg-[#1a1a1a] border border-white/10 px-4 py-2 rounded-md hover:bg-[#252525] transition-colors text-sm font-medium ${isTypeOpen ? 'bg-[#252525] border-white/30' : ''}`}>
                        <Type size={14} className="text-gray-400" />
                        <span className="hidden sm:inline">{TYPOGRAPHY_STYLES.find(t => t.id === currentSlide.typography)?.name || 'Font'}</span>
                        <ChevronDown size={14} className={`text-gray-400 transition-transform ${isTypeOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isTypeOpen && (
                        <div className="absolute top-full right-0 mt-2 w-48 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            {TYPOGRAPHY_STYLES.map(t => (
                                <button key={t.id} onClick={() => { onApplyTypography(t.id); setIsTypeOpen(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-white/5 transition-colors flex items-center justify-between ${currentSlide.typography === t.id ? 'text-indigo-400 font-medium' : 'text-gray-300'}`}>
                                    {t.name} {currentSlide.typography === t.id && <Check size={14} />}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                {/* Theme */}
                <div className="relative" ref={themeRef}>
                    <button onClick={() => setIsThemeOpen(!isThemeOpen)} className={`flex items-center gap-2 bg-[#1a1a1a] border border-white/10 px-4 py-2 rounded-md hover:bg-[#252525] transition-colors text-sm font-medium ${isThemeOpen ? 'bg-[#252525] border-white/30' : ''}`}>
                        <span className="hidden sm:inline">{THEMES.find(t => t.id === currentSlide.theme)?.name || 'Theme'}</span>
                        <ChevronDown size={14} className={`text-gray-400 transition-transform ${isThemeOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isThemeOpen && (
                        <div className="absolute top-full right-0 mt-2 w-48 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            {THEMES.map(t => (
                                <button key={t.id} onClick={() => { onApplyTheme(t.id); setIsThemeOpen(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-white/5 transition-colors flex items-center justify-between ${currentSlide.theme === t.id ? 'text-indigo-400 font-medium' : 'text-gray-300'}`}>
                                    {t.name} {currentSlide.theme === t.id && <Check size={14} />}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                {/* Random */}
                <button onClick={onRandomize} className="flex items-center gap-2 bg-[#1a1a1a] border border-white/10 px-3 py-2 rounded-md hover:bg-[#252525] transition-colors text-sm font-medium text-gray-400 hover:text-white group" title="Randomize Theme & Typography">
                    <Shuffle size={16} className="group-hover:text-indigo-400 transition-colors" />
                    <span className="hidden sm:inline">Random</span>
                </button>
            </div>

            {/* Right: Actions */}
            <div className="flex items-center gap-2">
                {/* Project */}
                <div className="relative" ref={projRef}>
                    <button onClick={() => setIsProjOpen(!isProjOpen)} className={`flex items-center gap-2 px-3 py-2 rounded-md transition-colors text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 ${isProjOpen ? 'bg-white/5 text-white' : ''}`}>
                        <FolderOpen size={20} /><span className="hidden sm:inline">Project</span><ChevronDown size={14} className={`transition-transform ${isProjOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isProjOpen && (
                        <div className="absolute top-full right-0 mt-2 w-48 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            <button onClick={() => { onNewProject(); setIsProjOpen(false); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex items-center gap-3 text-gray-200">
                                <FilePlus size={16} className="text-blue-400" /><div className="flex flex-col gap-0.5"><span className="font-medium">New Project</span><span className="text-[10px] text-gray-500">Start fresh</span></div>
                            </button>
                            <div className="h-px bg-white/5 mx-2"></div>
                            <button onClick={() => fileInputRef.current?.click()} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex items-center gap-3 text-gray-200">
                                <Upload size={16} className="text-indigo-400" /><div className="flex flex-col gap-0.5"><span className="font-medium">Open Project</span><span className="text-[10px] text-gray-500">Load .json file</span></div>
                            </button>
                            <div className="h-px bg-white/5 mx-2"></div>
                            <button onClick={() => { onSaveProject(); setIsProjOpen(false); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex items-center gap-3 text-gray-200">
                                <FileDown size={16} className="text-green-400" /><div className="flex flex-col gap-0.5"><span className="font-medium">Save Project</span><span className="text-[10px] text-gray-500">Download .json file</span></div>
                            </button>
                        </div>
                    )}
                </div>

                {/* Save Cloud */}
                <button onClick={onManualSave} className={`p-2 rounded-md transition-colors relative flex items-center justify-center ${saveStatus === 'error' ? 'text-red-500 hover:bg-red-500/10' : 'text-gray-400 hover:text-white hover:bg-white/5'}`} title="Force Save to Cloud">
                    {saveStatus === 'saving' ? <Loader2 size={20} className="animate-spin" /> : <Cloud size={20} />}
                </button>

                {/* Export */}
                <div className="relative" ref={expRef}>
                    <button onClick={() => setIsExpOpen(!isExpOpen)} className={`flex items-center gap-2 px-3 py-2 rounded-md transition-colors text-sm font-medium ${isExporting ? 'text-indigo-400 bg-indigo-500/10 cursor-not-allowed' : 'text-gray-400 hover:text-white hover:bg-white/5'} ${isExpOpen ? 'bg-white/5 text-white' : ''}`} disabled={isExporting}>
                        <Download size={20} /><span className="hidden sm:inline">Export</span><ChevronDown size={14} className={`transition-transform ${isExpOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isExpOpen && !isExporting && (
                        <div className="absolute top-full right-0 mt-2 w-48 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            <button onClick={() => { onOpenExport('current'); setIsExpOpen(false); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex flex-col gap-0.5">
                                <span className="text-gray-200 font-medium">Current Slide</span><span className="text-xs text-gray-500">Export this slide only</span>
                            </button>
                            <div className="h-px bg-white/5 mx-2"></div>
                            <button onClick={() => { onOpenExport('all'); setIsExpOpen(false); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex flex-col gap-0.5">
                                <span className="text-gray-200 font-medium">All Slides</span><span className="text-xs text-gray-500">Export full presentation</span>
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </header>
    );
};

export default TopBar;

import React from 'react';
import { Film, Settings, X, Monitor, Archive, FileImage, Image, List, CheckCircle, Loader2, AlertCircle, Trash2, Play } from 'lucide-react';
import { ExportJob, SlideData } from '../types';

interface ExportModalProps {
    isOpen: boolean;
    onClose: () => void;

    // UI State
    tab: 'settings' | 'queue';
    setTab: (t: 'settings' | 'queue') => void;

    // Export Settings
    scope: 'current' | 'all';
    slideCount: number;
    currentSlideBadge: string;

    quality: '720p' | '1080p' | '4k';
    setQuality: (q: '720p' | '1080p' | '4k') => void;

    bitrate: 'low' | 'medium' | 'high';
    setBitrate: (b: 'low' | 'medium' | 'high') => void;

    format: 'mp4' | 'zip';
    setFormat: (f: 'mp4' | 'zip') => void;

    imageFormat: 'jpeg' | 'png';
    setImageFormat: (f: 'jpeg' | 'png') => void;

    // Execution
    isExporting: boolean;
    progress: number;
    queue: ExportJob[];

    onQueue: () => void;
    onStart: () => void;
    onProcessQueue: () => void;
    onDeleteJob: (id: string) => void;
}

const ExportModal: React.FC<ExportModalProps> = ({
    isOpen, onClose, tab, setTab,
    scope, slideCount, currentSlideBadge,
    quality, setQuality, bitrate, setBitrate, format, setFormat, imageFormat, setImageFormat,
    isExporting, progress, queue,
    onQueue, onStart, onProcessQueue, onDeleteJob
}) => {
    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-in fade-in duration-200">
            <div className="bg-[#141414] border border-gray-800 rounded-xl shadow-2xl w-[550px] overflow-hidden flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className="flex items-center justify-between px-6 py-4 border-b border-gray-800 bg-[#1a1a1a] shrink-0">
                    <div className="flex items-center gap-2 text-white font-medium">
                        {isExporting ? <Film size={18} className="text-indigo-500"/> : <Settings size={18} className="text-gray-400"/>}
                        {isExporting ? "Processing Export..." : "Export Center"}
                    </div>
                    {!isExporting && (
                        <button onClick={onClose} className="text-gray-500 hover:text-white transition-colors">
                            <X size={20} />
                        </button>
                    )}
                </div>

                {/* Tabs */}
                {!isExporting && (
                    <div className="flex border-b border-gray-800 bg-[#1a1a1a] shrink-0">
                        <button onClick={() => setTab('settings')} className={`flex-1 py-3 text-sm font-medium transition-colors border-b-2 ${tab === 'settings' ? 'border-indigo-500 text-white bg-white/5' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>Export Settings</button>
                        <button onClick={() => setTab('queue')} className={`flex-1 py-3 text-sm font-medium transition-colors border-b-2 flex items-center justify-center gap-2 ${tab === 'queue' ? 'border-indigo-500 text-white bg-white/5' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>
                            Export Queue {queue.length > 0 && <span className="bg-indigo-500 text-white text-[10px] px-1.5 py-0.5 rounded-full">{queue.length}</span>}
                        </button>
                    </div>
                )}

                {/* Content */}
                <div className="p-6 space-y-6 overflow-y-auto flex-1 custom-scrollbar">

                    {/* Settings Tab */}
                    {!isExporting && tab === 'settings' && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-left-4 duration-300">
                            {/* Info */}
                            <div className="flex items-center gap-3 p-3 bg-indigo-500/10 border border-indigo-500/20 rounded-lg">
                                <Monitor className="text-indigo-400" size={20} />
                                <div className="flex-1">
                                    <div className="text-sm font-medium text-indigo-300">Exporting {scope === 'current' ? "Current Slide" : "All Slides"}</div>
                                    <div className="text-xs text-indigo-400/60">{scope === 'current' ? currentSlideBadge : `${slideCount} slides combined`}</div>
                                </div>
                            </div>

                            {/* Format */}
                            <div className="space-y-3">
                                <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Format</label>
                                <div className="grid grid-cols-2 gap-3">
                                    <button onClick={() => setFormat('mp4')} className={`flex items-center justify-center gap-3 py-3 rounded-lg border transition-all ${format === 'mp4' ? 'bg-white text-black border-white' : 'bg-[#1e1e1e] border-gray-700 text-gray-400'}`}><Film size={18}/><div className="flex flex-col items-start"><span className="font-bold text-sm">Video</span><span className="text-[10px] opacity-70">MP4</span></div></button>
                                    <button onClick={() => setFormat('zip')} className={`flex items-center justify-center gap-3 py-3 rounded-lg border transition-all ${format === 'zip' ? 'bg-white text-black border-white' : 'bg-[#1e1e1e] border-gray-700 text-gray-400'}`}><Archive size={18}/><div className="flex flex-col items-start"><span className="font-bold text-sm">Frames</span><span className="text-[10px] opacity-70">ZIP</span></div></button>
                                </div>
                            </div>

                            {/* Image Format (ZIP) */}
                            {format === 'zip' && (
                                <div className="space-y-3 animate-in fade-in duration-200">
                                    <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Image Format</label>
                                    <div className="grid grid-cols-2 gap-3">
                                        <button onClick={() => setImageFormat('jpeg')} className={`flex items-center justify-center gap-3 py-3 rounded-lg border transition-all ${imageFormat === 'jpeg' ? 'bg-white text-black border-white' : 'bg-[#1e1e1e] border-gray-700 text-gray-400'}`}><FileImage size={18}/><div className="flex flex-col items-start"><span className="font-bold text-sm">JPEG</span><span className="text-[10px] opacity-70">Small</span></div></button>
                                        <button onClick={() => setImageFormat('png')} className={`flex items-center justify-center gap-3 py-3 rounded-lg border transition-all ${imageFormat === 'png' ? 'bg-white text-black border-white' : 'bg-[#1e1e1e] border-gray-700 text-gray-400'}`}><Image size={18}/><div className="flex flex-col items-start"><span className="font-bold text-sm">PNG</span><span className="text-[10px] opacity-70">Lossless</span></div></button>
                                    </div>
                                </div>
                            )}

                            {/* Resolution */}
                            <div className="space-y-3">
                                <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Resolution</label>
                                <div className="grid grid-cols-3 gap-3">
                                    {(['720p', '1080p', '4k'] as const).map(res => (
                                        <button key={res} onClick={() => setQuality(res)} className={`flex flex-col items-center justify-center py-3 rounded-lg border transition-all ${quality === res ? 'bg-white text-black border-white' : 'bg-[#1e1e1e] border-gray-700 text-gray-400'}`}>
                                            <span className="font-bold text-lg">{res}</span>
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Bitrate (MP4) */}
                            {format === 'mp4' && (
                                <div className="space-y-3 animate-in fade-in duration-200">
                                    <label className="text-xs font-semibold text-gray-400 uppercase tracking-wider">Bitrate</label>
                                    <div className="grid grid-cols-3 gap-3">
                                        {(['low', 'medium', 'high'] as const).map(b => (
                                            <button key={b} onClick={() => setBitrate(b)} className={`flex flex-col items-center justify-center py-3 rounded-lg border transition-all ${bitrate === b ? 'bg-white text-black border-white' : 'bg-[#1e1e1e] border-gray-700 text-gray-400'}`}>
                                                <span className="font-bold text-sm capitalize">{b}</span>
                                            </button>
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    )}

                    {/* Queue Tab */}
                    {!isExporting && tab === 'queue' && (
                        <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                            {queue.length === 0 ? (
                                <div className="flex flex-col items-center justify-center py-10 text-gray-500 gap-3"><List size={40} className="opacity-20"/><span className="text-sm">No jobs. Add one from Settings!</span></div>
                            ) : (
                                <div className="space-y-3">
                                    {queue.map(job => (
                                        <div key={job.id} className="bg-[#1e1e1e] border border-gray-700 rounded-lg p-4 flex items-center justify-between group">
                                            <div className="flex items-center gap-3">
                                                <div className={`w-2 h-2 rounded-full ${job.status === 'completed' ? 'bg-green-500' : job.status === 'processing' ? 'bg-indigo-500 animate-pulse' : job.status === 'failed' ? 'bg-red-500' : 'bg-gray-500'}`}></div>
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-medium text-white flex items-center gap-2">{job.scope === 'current' ? (job.slides[0]?.badge || "Single") : "All Slides"}<span className="text-[10px] bg-gray-700 px-1.5 rounded text-gray-300 uppercase">{job.format}</span></span>
                                                    <span className="text-xs text-gray-500">{job.quality} • {new Date(job.createdAt).toLocaleTimeString()}</span>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                {job.status === 'processing' && <Loader2 size={16} className="animate-spin text-indigo-400" />}
                                                {job.status === 'completed' && <CheckCircle size={16} className="text-green-500" />}
                                                {job.status === 'failed' && <AlertCircle size={16} className="text-red-500" />}
                                                {job.status !== 'processing' && <button onClick={() => onDeleteJob(job.id)} className="p-1.5 hover:bg-red-500/20 text-gray-500 hover:text-red-400 rounded transition-colors"><Trash2 size={16} /></button>}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}

                    {/* Processing View */}
                    {isExporting && (
                        <div className="space-y-6 py-4 animate-in fade-in duration-300">
                            <div className="flex flex-col items-center justify-center gap-4 text-center">
                                {progress < 100 ? <div className="w-16 h-16 rounded-full border-4 border-indigo-500/30 border-t-indigo-500 animate-spin"></div> : <div className="w-16 h-16 rounded-full bg-green-500/20 text-green-500 flex items-center justify-center animate-in zoom-in"><CheckCircle size={32} /></div>}
                                <div><div className="text-xl font-bold text-white mb-1">{progress}%</div><div className="text-sm text-gray-400">{progress < 100 ? "Rendering frames..." : "Finalizing..."}</div></div>
                            </div>
                            <div className="w-full bg-gray-800 rounded-full h-2 overflow-hidden"><div className="h-full bg-indigo-500 transition-all duration-300 ease-out" style={{ width: `${progress}%` }}></div></div>
                        </div>
                    )}
                </div>

                {/* Footer */}
                <div className="px-6 py-4 bg-[#1a1a1a] border-t border-gray-800 flex justify-end gap-3 shrink-0">
                    {!isExporting && (
                        <>
                            {tab === 'settings' ? (
                                <><button onClick={onQueue} className="px-4 py-2 text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 rounded-md transition-colors flex items-center gap-2"><List size={16}/>Queue Export</button><button onClick={onStart} className="px-6 py-2 bg-white text-black text-sm font-bold rounded-md hover:bg-gray-200 transition-colors">Start Export</button></>
                            ) : (
                                <><button onClick={onClose} className="px-4 py-2 text-sm font-medium text-gray-400 hover:text-white">Close</button><button onClick={onProcessQueue} disabled={queue.filter(j => j.status === 'pending').length === 0} className={`px-6 py-2 bg-indigo-600 text-white text-sm font-bold rounded-md transition-colors flex items-center gap-2 ${queue.filter(j => j.status === 'pending').length === 0 ? 'opacity-50 cursor-not-allowed' : 'hover:bg-indigo-500'}`}><Play size={16} fill="currentColor"/>Process Queue</button></>
                            )}
                        </>
                    )}
                    {isExporting && <div className="text-xs text-gray-500 italic self-center">Please do not close this window</div>}
                </div>
            </div>
        </div>
    );
};

export default ExportModal;

import React, { useRef } from 'react';
import EditorSidebar from './components/EditorSidebar';
import SlideRenderer from './components/SlideRenderer';
import PreviewControls from './components/PreviewControls';
import LoadingScreen from './components/LoadingScreen';
import HiddenExportRenderer from './components/HiddenExportRenderer';
import TopBar from './components/TopBar';
import ExportModal from './components/ExportModal';

import { usePresentation } from './hooks/usePresentation';
import { usePlayback } from './hooks/usePlayback';
import { useScale } from './hooks/useScale';
import { useExportManager } from './hooks/useExportManager';

const App: React.FC = () => {
    // 1. Data & Persistence
    const {
        slides, currentSlideIndex, currentSlide, saveStatus, isLoaded,
        setCurrentSlideIndex, updateSlide, addSlide, duplicateSlide, deleteSlide, reorderSlide,
        manualSave, applyTheme, applyTypography, randomizeLook,
        newProject, loadProject, saveProject
    } = usePresentation();

    // 2. Playback
    const { isPlaying, progress, togglePlay, scrub } = usePlayback(currentSlide?.duration);

    // 3. Render Helpers
    const containerRef = useRef<HTMLDivElement>(null);
    const scale = useScale(containerRef);

    // 4. Export Management
    const hiddenExportRef = useRef<HTMLDivElement>(null);
    const exportManager = useExportManager(slides, currentSlide, hiddenExportRef);

    // Loading State
    if (!isLoaded && !currentSlide) return <LoadingScreen />;

    return (
        <div className="flex h-screen w-screen bg-[#050505] text-white flex-col relative">

            {/* Hidden Renderer for Export Operations */}
            <HiddenExportRenderer 
                ref={hiddenExportRef} 
                slide={exportManager.exportingSlide || currentSlide} 
                progress={exportManager.exportRenderProgress} 
            />

            {/* Top Navigation Bar */}
            <TopBar 
                currentSlide={currentSlide}
                saveStatus={saveStatus}
                isExporting={exportManager.isExporting}
                onApplyTheme={applyTheme}
                onApplyTypography={applyTypography}
                onRandomize={randomizeLook}
                onManualSave={manualSave}
                onNewProject={newProject}
                onLoadProject={loadProject}
                onSaveProject={saveProject}
                onOpenExport={exportManager.openExportModal}
            />

            {/* Main Workspace */}
            <div className="flex-1 flex overflow-hidden">
                {/* Left: Preview Area */}
                <div className="flex-1 relative bg-[#050505] flex items-center justify-center overflow-hidden" ref={containerRef}>
                    <div className="relative shadow-2xl shadow-black">
                        {/* We reset key when critical slide props change to restart animations if needed, mostly handled by SlideRenderer internal logic though */}
                        <SlideRenderer 
                            key={`${currentSlide.id}-${currentSlide.textTransition}`} 
                            data={currentSlide} 
                            scale={scale}
                            progress={progress}
                        />
                    </div>

                    <PreviewControls 
                        currentSlideIndex={currentSlideIndex + 1} 
                        totalSlides={slides.length} 
                        onNext={() => currentSlideIndex < slides.length - 1 && setCurrentSlideIndex(currentSlideIndex + 1)} 
                        onPrev={() => currentSlideIndex > 0 && setCurrentSlideIndex(currentSlideIndex - 1)} 
                        isPlaying={isPlaying}
                        onTogglePlay={togglePlay}
                        progress={progress}
                        onScrub={scrub}
                    />
                </div>

                {/* Right: Editor Sidebar */}
                <EditorSidebar 
                    slides={slides}
                    currentSlideIndex={currentSlideIndex}
                    onUpdateSlide={updateSlide}
                    onAddSlide={addSlide}
                    onDuplicateSlide={duplicateSlide}
                    onDeleteSlide={deleteSlide}
                    onSelectSlide={setCurrentSlideIndex}
                    onReorderSlides={reorderSlide}
                />
            </div>

            {/* Export Modal */}
            <ExportModal 
                isOpen={exportManager.isExportModalOpen}
                onClose={() => exportManager.setIsExportModalOpen(false)}
                tab={exportManager.exportModalTab}
                setTab={exportManager.setExportModalTab}
                scope={exportManager.exportScope}
                slideCount={slides.length}
                currentSlideBadge={currentSlide.badge}
                quality={exportManager.exportQuality}
                setQuality={exportManager.setExportQuality}
                bitrate={exportManager.exportBitrate}
                setBitrate={exportManager.setExportBitrate}
                format={exportManager.exportFormat}
                setFormat={exportManager.setExportFormat}
                imageFormat={exportManager.exportImageFormat}
                setImageFormat={exportManager.setExportImageFormat}
                isExporting={exportManager.isExporting}
                progress={exportManager.exportProgressStatus}
                queue={exportManager.exportQueue}
                onQueue={exportManager.queueExport}
                onStart={() => exportManager.executeExport()}
                onProcessQueue={exportManager.processQueue}
                onDeleteJob={exportManager.deleteJob}
            />

        </div>
    );
};

export default App;

import { useState, useEffect, useRef } from 'react';
import { SlideData, INITIAL_SLIDE, createNewSlide, SlideLayout, ThemeId, TypographyId, THEMES, TYPOGRAPHY_STYLES } from '../types';
import { supabase } from '../services/supabaseClient';

export const usePresentation = () => {
    const [slides, setSlides] = useState<SlideData[]>([INITIAL_SLIDE]);
    const [currentSlideIndex, setCurrentSlideIndex] = useState(0);
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
    const [isLoaded, setIsLoaded] = useState(false);
    const isFirstLoad = useRef(true);

    const currentSlide = slides[currentSlideIndex] || slides[0];

    // --- Persistence Logic ---

    // Load
    useEffect(() => {
        const loadData = async () => {
            try {
                const { data, error } = await supabase
                    .from('presentations')
                    .select('slides')
                    .eq('id', 1)
                    .single();

                if (error) {
                    console.log("Supabase load info:", error.message);
                } else if (data && data.slides && Array.isArray(data.slides) && data.slides.length > 0) {
                    setSlides(data.slides);
                }
            } catch (e) {
                console.error("Failed to fetch from supabase:", e);
            } finally {
                setIsLoaded(true);
                setTimeout(() => { isFirstLoad.current = false; }, 500);
            }
        };
        loadData();
    }, []);

    // Save Helper
    const saveToCloud = async (slidesToSave: SlideData[]) => {
        setSaveStatus('saving');
        try {
            const { error } = await supabase.from('presentations').upsert({ id: 1, slides: slidesToSave });
            if (error) throw error;
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 2000);
        } catch (error: any) {
            console.error("Failed to save to Supabase:", error);
            setSaveStatus('error');
        }
    };

    // Auto-Save
    useEffect(() => {
        if (!isLoaded || isFirstLoad.current) return;
        const timeoutId = setTimeout(() => {
            saveToCloud(slides);
        }, 2000);
        return () => clearTimeout(timeoutId);
    }, [slides, isLoaded]);


    // --- Slide Operations ---

    const handleUpdateSlide = (updatedSlide: SlideData) => {
        // Universal Changes logic from original App.tsx
        const oldSlide = slides[currentSlideIndex];
        let newSlides = slides.map((s, index) => index === currentSlideIndex ? updatedSlide : s);

        // Apply Global changes if these specific fields changed
        if (oldSlide.theme !== updatedSlide.theme) {
            newSlides = newSlides.map(s => ({ ...s, theme: updatedSlide.theme }));
        }
        if (oldSlide.typography !== updatedSlide.typography) {
            newSlides = newSlides.map(s => ({ ...s, typography: updatedSlide.typography }));
        }
        if (oldSlide.textTransition !== updatedSlide.textTransition) {
            newSlides = newSlides.map(s => ({ ...s, textTransition: updatedSlide.textTransition }));
        }
        if (oldSlide.imageTransition !== updatedSlide.imageTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageTransition: updatedSlide.imageTransition }));
        }
        if (oldSlide.textOutroTransition !== updatedSlide.textOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, textOutroTransition: updatedSlide.textOutroTransition }));
        }
        if (oldSlide.imageOutroTransition !== updatedSlide.imageOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageOutroTransition: updatedSlide.imageOutroTransition }));
        }

        setSlides(newSlides);
    };

    const handleAddSlide = (layout: SlideLayout = 'text-image') => {
        const newSlide = createNewSlide(layout);
        const refSlide = slides[currentSlideIndex] || slides[0];
        // Inherit styles
        newSlide.theme = refSlide.theme || 'cyber-future';
        newSlide.typography = refSlide.typography || 'modern-sans';
        newSlide.textTransition = refSlide.textTransition || 'slide-up';
        newSlide.imageTransition = refSlide.imageTransition || 'zoom-in';
        newSlide.textOutroTransition = refSlide.textOutroTransition || 'none';
        newSlide.imageOutroTransition = refSlide.imageOutroTransition || 'none';

        // Auto-increment badge step
        const lastSlide = slides[slides.length - 1];
        if (lastSlide && lastSlide.badge.startsWith('Step ')) {
            const num = parseInt(lastSlide.badge.split(' ')[1]);
            if (!isNaN(num)) newSlide.badge = `Step ${num + 1}`;
        }

        setSlides([...slides, newSlide]);
        setCurrentSlideIndex(slides.length);
    };

    const handleDuplicateSlide = (index: number) => {
        const slide = slides[index];
        if (!slide) return;
        const newSlide = { ...slide, id: Date.now().toString() };
        const newSlides = [...slides];
        newSlides.splice(index + 1, 0, newSlide);
        setSlides(newSlides);
        setCurrentSlideIndex(index + 1);
    };

    const handleDeleteSlide = (index: number) => {
        if (slides.length <= 1) return;
        const newSlides = slides.filter((_, i) => i !== index);
        setSlides(newSlides);
        if (currentSlideIndex >= index && currentSlideIndex > 0) {
            setCurrentSlideIndex(currentSlideIndex - 1);
        } else if (currentSlideIndex >= newSlides.length) {
            setCurrentSlideIndex(newSlides.length - 1);
        }
    };

    const handleReorderSlides = (from: number, to: number) => {
        if (from === to) return;
        const newSlides = [...slides];
        const [moved] = newSlides.splice(from, 1);
        newSlides.splice(to, 0, moved);
        setSlides(newSlides);

        if (currentSlideIndex === from) setCurrentSlideIndex(to);
        else if (from < currentSlideIndex && to >= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex - 1);
        else if (from > currentSlideIndex && to <= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex + 1);
    };

    const applyTheme = (id: ThemeId) => setSlides(slides.map(s => ({ ...s, theme: id })));
    const applyTypography = (id: TypographyId) => setSlides(slides.map(s => ({ ...s, typography: id })));

    const randomizeLook = () => {
        const t = THEMES[Math.floor(Math.random() * THEMES.length)];
        const f = TYPOGRAPHY_STYLES[Math.floor(Math.random() * TYPOGRAPHY_STYLES.length)];
        setSlides(slides.map(s => ({ ...s, theme: t.id, typography: f.id })));
    };

    // Project File Management
    const newProject = () => {
        if (window.confirm("Start new project? Unsaved changes will be lost.")) {
            // Updated: Create a fresh new slide using the Text+Image layout default
            const freshSlide = createNewSlide('text-image');
            setSlides([freshSlide]);
            setCurrentSlideIndex(0);
            setTimeout(() => saveToCloud([freshSlide]), 500);
        }
    };

    const loadProject = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target?.result as string);
                if (Array.isArray(json) && json.length > 0 && json[0].id) {
                    setSlides(json as SlideData[]);
                    setCurrentSlideIndex(0);
                    setTimeout(() => saveToCloud(json), 500);
                } else {
                    alert("Invalid project file.");
                }
            } catch (err) {
                console.error(err);
                alert("Failed to parse project file.");
            }
        };
        reader.readAsText(file);
    };

    const saveProject = () => {
        try {
            const blob = new Blob([JSON.stringify(slides, null, 2)], { type: "application/json" });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `slideforge-${new Date().toISOString().slice(0, 10)}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch(e) { console.error(e); }
    };

    return {
        slides,
        currentSlideIndex,
        currentSlide,
        saveStatus,
        isLoaded,
        setSlides,
        setCurrentSlideIndex,
        updateSlide: handleUpdateSlide,
        addSlide: handleAddSlide,
        duplicateSlide: handleDuplicateSlide,
        deleteSlide: handleDeleteSlide,
        reorderSlide: handleReorderSlides,
        manualSave: () => saveToCloud(slides),
        applyTheme,
        applyTypography,
        randomizeLook,
        newProject,
        loadProject,
        saveProject
    };
};

