import React, { useState, useRef } from 'react';
import { LayoutTemplate, Plus, Upload, FileText, Calendar, Trash2, Edit2, Search, X, Loader2 } from 'lucide-react';
import { ProjectMetadata } from '../types';

interface WelcomeScreenProps {
    isOpen: boolean;
    onClose: () => void;
    recentProjects: ProjectMetadata[];
    isLoadingProjects: boolean;
    onNewProject: () => void;
    onLoadProject: (id: string | number) => void;
    onImportProject: (file: File) => void;
    onRenameProject: (id: string | number, newName: string) => void;
    onDeleteProject: (id: string | number) => void;
}

const WelcomeScreen: React.FC<WelcomeScreenProps> = ({
    isOpen, onClose,
    recentProjects, isLoadingProjects,
    onNewProject, onLoadProject, onImportProject, onRenameProject, onDeleteProject
}) => {
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [editingId, setEditingId] = useState<string | number | null>(null);
    const [editName, setEditName] = useState('');

    if (!isOpen) return null;

    const filteredProjects = recentProjects.filter(p => 
        p.name.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const handleStartRename = (project: ProjectMetadata) => {
        setEditingId(project.id);
        setEditName(project.name);
    };

    const handleFinishRename = () => {
        if (editingId && editName.trim()) {
            onRenameProject(editingId, editName);
        }
        setEditingId(null);
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') handleFinishRename();
        if (e.key === 'Escape') setEditingId(null);
    };

    return (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-[#050505]/95 backdrop-blur-md animate-in fade-in duration-300">
            <div className="w-full max-w-5xl h-[80vh] bg-[#101010] border border-white/10 rounded-2xl shadow-2xl flex overflow-hidden">

                {/* Left Sidebar: Actions */}
                <div className="w-80 bg-[#161616] border-r border-white/5 p-8 flex flex-col gap-8">
                    <div className="flex items-center gap-3 mb-4">
                        <div className="w-10 h-10 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-500/20">
                            <LayoutTemplate size={24} className="text-white" />
                        </div>
                        <div>
                            <h1 className="font-bold text-xl tracking-tight text-white">SlideForge</h1>
                            <p className="text-xs text-gray-500">Presentation Editor</p>
                        </div>
                    </div>

                    <div className="space-y-4">
                        <button 
                            onClick={onNewProject}
                            className="w-full py-4 px-6 bg-white text-black font-bold rounded-xl hover:bg-gray-200 transition-colors flex items-center gap-3 shadow-lg group"
                        >
                            <div className="w-8 h-8 rounded-full bg-black/10 flex items-center justify-center group-hover:scale-110 transition-transform">
                                <Plus size={18} />
                            </div>
                            <span>New Project</span>
                        </button>

                        <button 
                            onClick={() => fileInputRef.current?.click()}
                            className="w-full py-4 px-6 bg-white/5 border border-white/10 text-gray-300 font-medium rounded-xl hover:bg-white/10 hover:text-white transition-all flex items-center gap-3 group"
                        >
                            <div className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center group-hover:bg-white/10 transition-colors">
                                <Upload size={18} />
                            </div>
                            <span>Import JSON</span>
                            <input 
                                type="file" 
                                ref={fileInputRef} 
                                accept=".json" 
                                className="hidden" 
                                onChange={(e) => {
                                    if(e.target.files?.[0]) onImportProject(e.target.files[0]);
                                }}
                            />
                        </button>
                    </div>

                    <div className="mt-auto">
                        <button onClick={onClose} className="text-gray-500 hover:text-white text-sm transition-colors flex items-center gap-2">
                           <X size={16} /> Close & Return to Editor
                        </button>
                    </div>
                </div>

                {/* Right Content: Recent Files */}
                <div className="flex-1 flex flex-col bg-[#0a0a0a]">
                    <div className="p-8 pb-4 border-b border-white/5 flex items-center justify-between">
                        <h2 className="text-2xl font-bold text-white">Recent Projects</h2>
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500" size={16} />
                            <input 
                                type="text" 
                                placeholder="Search projects..." 
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                                className="bg-[#1a1a1a] border border-white/10 rounded-lg pl-10 pr-4 py-2 text-sm text-white focus:outline-none focus:border-indigo-500/50 w-64 transition-all"
                            />
                        </div>
                    </div>

                    <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
                        {isLoadingProjects ? (
                            <div className="flex flex-col items-center justify-center h-64 text-gray-500 gap-3">
                                <Loader2 size={32} className="animate-spin text-indigo-500" />
                                <p>Syncing with cloud...</p>
                            </div>
                        ) : filteredProjects.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-64 text-gray-600 border-2 border-dashed border-white/5 rounded-xl">
                                <FileText size={48} className="mb-4 opacity-20" />
                                <p className="text-lg font-medium">No projects found</p>
                                <p className="text-sm">Create a new one or import a file to get started.</p>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 gap-3">
                                {filteredProjects.map((project) => (
                                    <div 
                                        key={project.id} 
                                        className="group flex items-center justify-between p-4 bg-[#141414] border border-white/5 rounded-xl hover:border-indigo-500/30 hover:bg-[#1a1a1a] transition-all cursor-pointer"
                                        onClick={() => {
                                            if (editingId !== project.id) onLoadProject(project.id);
                                        }}
                                    >
                                        <div className="flex items-center gap-4 flex-1">
                                            <div className="w-12 h-12 rounded-lg bg-gradient-to-br from-gray-800 to-gray-900 flex items-center justify-center border border-white/5 group-hover:from-indigo-900/20 group-hover:to-purple-900/20 transition-colors">
                                                <LayoutTemplate size={20} className="text-gray-400 group-hover:text-indigo-400" />
                                            </div>

                                            <div className="flex flex-col flex-1">
                                                {editingId === project.id ? (
                                                    <input 
                                                        type="text" 
                                                        value={editName}
                                                        onChange={(e) => setEditName(e.target.value)}
                                                        onBlur={handleFinishRename}
                                                        onKeyDown={handleKeyDown}
                                                        autoFocus
                                                        className="bg-[#2a2a2a] text-white px-2 py-1 rounded border border-indigo-500 focus:outline-none text-sm font-medium w-full max-w-xs"
                                                        onClick={(e) => e.stopPropagation()}
                                                    />
                                                ) : (
                                                    <h3 className="font-medium text-white group-hover:text-indigo-200 transition-colors truncate">
                                                        {project.name || 'Untitled Project'}
                                                    </h3>
                                                )}
                                                <div className="flex items-center gap-2 text-xs text-gray-500 mt-1">
                                                    <Calendar size={12} />
                                                    <span>{new Date(project.updated_at).toLocaleDateString()} at {new Date(project.updated_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                                                </div>
                                            </div>
                                        </div>

                                        <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    handleStartRename(project);
                                                }}
                                                className="p-2 text-gray-500 hover:text-white hover:bg-white/10 rounded-lg transition-colors"
                                                title="Rename"
                                            >
                                                <Edit2 size={16} />
                                            </button>
                                            <button 
                                                onClick={(e) => {
                                                    e.stopPropagation();
                                                    if(window.confirm('Are you sure you want to delete this project?')) onDeleteProject(project.id);
                                                }}
                                                className="p-2 text-gray-500 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors"
                                                title="Delete"
                                            >
                                                <Trash2 size={16} />
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                </div>

            </div>
        </div>
    );
};

export default WelcomeScreen;

import { useState, useEffect, useRef } from 'react';
import { SlideData, INITIAL_SLIDE, createNewSlide, SlideLayout, ThemeId, TypographyId, THEMES, TYPOGRAPHY_STYLES, ProjectMetadata } from '../types';
import { supabase } from '../services/supabaseClient';

export const usePresentation = () => {
    // Current Project State
    const [currentProjectId, setCurrentProjectId] = useState<string | number | null>(null);
    const [currentProjectName, setCurrentProjectName] = useState<string>("Untitled Project");
    const [slides, setSlides] = useState<SlideData[]>([INITIAL_SLIDE]);
    const [currentSlideIndex, setCurrentSlideIndex] = useState(0);

    // App State
    const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved' | 'error'>('idle');
    const [isLoaded, setIsLoaded] = useState(false);
    const isFirstLoad = useRef(true);

    // Project List State
    const [savedProjects, setSavedProjects] = useState<ProjectMetadata[]>([]);
    const [isLoadingProjects, setIsLoadingProjects] = useState(false);

    const currentSlide = slides[currentSlideIndex] || slides[0];

    // --- Persistence Logic ---

    // Fetch Project List
    const fetchProjects = async () => {
        setIsLoadingProjects(true);
        try {
            // Select relevant fields. Order by updated_at descending
            const { data, error } = await supabase
                .from('presentations')
                .select('id, name, updated_at')
                .order('updated_at', { ascending: false });

            if (error) throw error;
            if (data) {
                setSavedProjects(data as ProjectMetadata[]);
            }
        } catch (e) {
            console.error("Failed to fetch projects list:", e);
        } finally {
            setIsLoadingProjects(false);
        }
    };

    // Initial Load of Project List
    useEffect(() => {
        fetchProjects();
        // Don't auto-load a specific project initially, wait for user selection
        // unless there is no project at all, but the Welcome Screen handles that.
        setIsLoaded(true);
        setTimeout(() => { isFirstLoad.current = false; }, 500);
    }, []);

    // Load Specific Project
    const loadRemoteProject = async (id: string | number) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .select('*')
                .eq('id', id)
                .single();

            if (error) throw error;
            if (data) {
                setSlides(data.slides || [INITIAL_SLIDE]);
                setCurrentProjectId(data.id);
                setCurrentProjectName(data.name || "Untitled");
                setCurrentSlideIndex(0);
            }
        } catch (e) {
            console.error("Failed to load project:", e);
            alert("Could not load project.");
        } finally {
            setIsLoaded(true);
        }
    };

    // Create New Remote Project
    const createNewRemoteProject = async (name: string, initialSlides: SlideData[]) => {
        setIsLoaded(false);
        try {
            const { data, error } = await supabase
                .from('presentations')
                .insert([{
                    name: name,
                    slides: initialSlides,
                    updated_at: new Date().toISOString()
                }])
                .select()
                .single();

            if (error) throw error;
            if (data) {
                setCurrentProjectId(data.id);
                setCurrentProjectName(data.name);
                setSlides(initialSlides);
                setCurrentSlideIndex(0);
                fetchProjects(); // Refresh list
            }
        } catch (e) {
            console.error("Failed to create project:", e);
            // Fallback for offline or error: just set state
            setSlides(initialSlides);
            setCurrentProjectName(name);
            setCurrentProjectId(Date.now()); // Temp ID
            setCurrentSlideIndex(0);
        } finally {
            setIsLoaded(true);
        }
    };

    // Save Helper
    const saveToCloud = async (slidesToSave: SlideData[]) => {
        if (!currentProjectId) return; // Can't save without an ID (should be created via createNewRemoteProject first usually)

        setSaveStatus('saving');
        try {
            const { error } = await supabase
                .from('presentations')
                .upsert({ 
                    id: currentProjectId, 
                    name: currentProjectName,
                    slides: slidesToSave,
                    updated_at: new Date().toISOString()
                });

            if (error) throw error;
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 2000);
            fetchProjects(); // Refresh list to update timestamp
        } catch (error: any) {
            console.error("Failed to save to Supabase:", error);
            setSaveStatus('error');
        }
    };

    // Rename Project
    const renameProject = async (id: string | number, newName: string) => {
        try {
            const { error } = await supabase
                .from('presentations')
                .update({ name: newName })
                .eq('id', id);

            if (error) throw error;

            // Update local state if it's the active project
            if (id === currentProjectId) {
                setCurrentProjectName(newName);
            }
            fetchProjects();
        } catch (e) {
            console.error("Failed to rename:", e);
        }
    };

    // Delete Project
    const deleteProject = async (id: string | number) => {
        try {
            const { error } = await supabase
                .from('presentations')
                .delete()
                .eq('id', id);

            if (error) throw error;

            // If deleted current project, unload it? Or just let it stay in memory until switch
            if (id === currentProjectId) {
                setCurrentProjectId(null); // Optional: kick to welcome screen logic handled by UI
            }
            fetchProjects();
        } catch (e) {
            console.error("Failed to delete:", e);
        }
    };

    // Auto-Save
    useEffect(() => {
        if (!isLoaded || isFirstLoad.current || !currentProjectId) return;
        const timeoutId = setTimeout(() => {
            saveToCloud(slides);
        }, 2000);
        return () => clearTimeout(timeoutId);
    }, [slides, isLoaded, currentProjectId, currentProjectName]);


    // --- Slide Operations ---

    const handleUpdateSlide = (updatedSlide: SlideData) => {
        const oldSlide = slides[currentSlideIndex];
        let newSlides = slides.map((s, index) => index === currentSlideIndex ? updatedSlide : s);

        // Apply Global changes logic
        if (oldSlide.theme !== updatedSlide.theme) {
            newSlides = newSlides.map(s => ({ ...s, theme: updatedSlide.theme }));
        }
        if (oldSlide.typography !== updatedSlide.typography) {
            newSlides = newSlides.map(s => ({ ...s, typography: updatedSlide.typography }));
        }
        if (oldSlide.textTransition !== updatedSlide.textTransition) {
            newSlides = newSlides.map(s => ({ ...s, textTransition: updatedSlide.textTransition }));
        }
        if (oldSlide.imageTransition !== updatedSlide.imageTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageTransition: updatedSlide.imageTransition }));
        }
        if (oldSlide.textOutroTransition !== updatedSlide.textOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, textOutroTransition: updatedSlide.textOutroTransition }));
        }
        if (oldSlide.imageOutroTransition !== updatedSlide.imageOutroTransition) {
            newSlides = newSlides.map(s => ({ ...s, imageOutroTransition: updatedSlide.imageOutroTransition }));
        }

        setSlides(newSlides);
    };

    const handleAddSlide = (layout: SlideLayout = 'text-image') => {
        const newSlide = createNewSlide(layout);
        const refSlide = slides[currentSlideIndex] || slides[0];
        // Inherit styles
        newSlide.theme = refSlide.theme || 'cyber-future';
        newSlide.typography = refSlide.typography || 'modern-sans';
        newSlide.textTransition = refSlide.textTransition || 'slide-up';
        newSlide.imageTransition = refSlide.imageTransition || 'zoom-in';
        newSlide.textOutroTransition = refSlide.textOutroTransition || 'none';
        newSlide.imageOutroTransition = refSlide.imageOutroTransition || 'none';

        const lastSlide = slides[slides.length - 1];
        if (lastSlide && lastSlide.badge.startsWith('Step ')) {
            const num = parseInt(lastSlide.badge.split(' ')[1]);
            if (!isNaN(num)) newSlide.badge = `Step ${num + 1}`;
        }

        setSlides([...slides, newSlide]);
        setCurrentSlideIndex(slides.length);
    };

    const handleDuplicateSlide = (index: number) => {
        const slide = slides[index];
        if (!slide) return;
        const newSlide = { ...slide, id: Date.now().toString() };
        const newSlides = [...slides];
        newSlides.splice(index + 1, 0, newSlide);
        setSlides(newSlides);
        setCurrentSlideIndex(index + 1);
    };

    const handleDeleteSlide = (index: number) => {
        if (slides.length <= 1) return;
        const newSlides = slides.filter((_, i) => i !== index);
        setSlides(newSlides);
        if (currentSlideIndex >= index && currentSlideIndex > 0) {
            setCurrentSlideIndex(currentSlideIndex - 1);
        } else if (currentSlideIndex >= newSlides.length) {
            setCurrentSlideIndex(newSlides.length - 1);
        }
    };

    const handleReorderSlides = (from: number, to: number) => {
        if (from === to) return;
        const newSlides = [...slides];
        const [moved] = newSlides.splice(from, 1);
        newSlides.splice(to, 0, moved);
        setSlides(newSlides);

        if (currentSlideIndex === from) setCurrentSlideIndex(to);
        else if (from < currentSlideIndex && to >= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex - 1);
        else if (from > currentSlideIndex && to <= currentSlideIndex) setCurrentSlideIndex(currentSlideIndex + 1);
    };

    const applyTheme = (id: ThemeId) => setSlides(slides.map(s => ({ ...s, theme: id })));
    const applyTypography = (id: TypographyId) => setSlides(slides.map(s => ({ ...s, typography: id })));

    const randomizeLook = () => {
        const t = THEMES[Math.floor(Math.random() * THEMES.length)];
        const f = TYPOGRAPHY_STYLES[Math.floor(Math.random() * TYPOGRAPHY_STYLES.length)];
        setSlides(slides.map(s => ({ ...s, theme: t.id, typography: f.id })));
    };

    // --- New Project Management ---

    // Starts a brand new project, defaulting to current date name
    const startNewProject = () => {
        const dateStr = new Date().toLocaleString();
        const name = `Project - ${dateStr}`;
        const freshSlide = createNewSlide('text-image');

        createNewRemoteProject(name, [freshSlide]);
    };

    // Imports a JSON file as a new project
    const importProjectFile = (file: File) => {
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
                const json = JSON.parse(e.target?.result as string);
                if (Array.isArray(json) && json.length > 0 && json[0].id) {
                    // Create as new project in DB
                    const dateStr = new Date().toLocaleString();
                    const name = `Imported - ${dateStr}`;
                    createNewRemoteProject(name, json as SlideData[]);
                } else {
                    alert("Invalid project file.");
                }
            } catch (err) {
                console.error(err);
                alert("Failed to parse project file.");
            }
        };
        reader.readAsText(file);
    };

    // Download current JSON
    const downloadProjectFile = () => {
        try {
            const blob = new Blob([JSON.stringify(slides, null, 2)], { type: "application/json" });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${currentProjectName.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        } catch(e) { console.error(e); }
    };

    return {
        // State
        slides,
        currentSlideIndex,
        currentSlide,
        saveStatus,
        isLoaded,
        currentProjectId,
        currentProjectName,
        savedProjects,
        isLoadingProjects,

        // Setters
        setSlides,
        setCurrentSlideIndex,

        // Actions
        updateSlide: handleUpdateSlide,
        addSlide: handleAddSlide,
        duplicateSlide: handleDuplicateSlide,
        deleteSlide: handleDeleteSlide,
        reorderSlide: handleReorderSlides,
        manualSave: () => saveToCloud(slides),

        // Styles
        applyTheme,
        applyTypography,
        randomizeLook,

        // Project Management
        startNewProject,
        loadRemoteProject,
        importProjectFile,
        downloadProjectFile,
        renameProject,
        deleteProject,
        fetchProjects
    };
};

import React, { useRef, useState, useEffect } from 'react';
import { LayoutTemplate, Cloud, Loader2, AlertCircle, Type, ChevronDown, Check, Shuffle, FolderOpen, FilePlus, Upload, FileDown, Download, Home } from 'lucide-react';
import { SlideData, ThemeId, THEMES, TypographyId, TYPOGRAPHY_STYLES } from '../types';

interface TopBarProps {
    currentSlide: SlideData;
    currentProjectName: string;
    saveStatus: 'idle' | 'saving' | 'saved' | 'error';
    isExporting: boolean;
    onApplyTheme: (id: ThemeId) => void;
    onApplyTypography: (id: TypographyId) => void;
    onRandomize: () => void;
    onManualSave: () => void;
    onNewProject: () => void;
    onLoadProject: (file: File) => void;
    onSaveProject: () => void;
    onOpenExport: (scope: 'current' | 'all') => void;
    onOpenWelcome: () => void;
}

const TopBar: React.FC<TopBarProps> = ({
    currentSlide, currentProjectName, saveStatus, isExporting,
    onApplyTheme, onApplyTypography, onRandomize, onManualSave,
    onNewProject, onLoadProject, onSaveProject, onOpenExport, onOpenWelcome
}) => {
    const [isThemeOpen, setIsThemeOpen] = useState(false);
    const [isTypeOpen, setIsTypeOpen] = useState(false);
    const [isProjOpen, setIsProjOpen] = useState(false);
    const [isExpOpen, setIsExpOpen] = useState(false);

    const themeRef = useRef<HTMLDivElement>(null);
    const typeRef = useRef<HTMLDivElement>(null);
    const projRef = useRef<HTMLDivElement>(null);
    const expRef = useRef<HTMLDivElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    // Click outside handler
    useEffect(() => {
        const handleClick = (e: MouseEvent) => {
            const target = e.target as Node;
            if (themeRef.current && !themeRef.current.contains(target)) setIsThemeOpen(false);
            if (typeRef.current && !typeRef.current.contains(target)) setIsTypeOpen(false);
            if (projRef.current && !projRef.current.contains(target)) setIsProjOpen(false);
            if (expRef.current && !expRef.current.contains(target)) setIsExpOpen(false);
        };
        document.addEventListener('mousedown', handleClick);
        return () => document.removeEventListener('mousedown', handleClick);
    }, []);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files?.[0]) {
            onLoadProject(e.target.files[0]);
            e.target.value = '';
        }
        setIsProjOpen(false);
    };

    return (
        <header className="h-16 border-b border-white/10 bg-[#0f0f0f] flex items-center justify-between px-6 shrink-0 z-50">
            <input type="file" accept=".json" ref={fileInputRef} onChange={handleFileChange} className="hidden" />

            {/* Left: Branding & Status */}
            <div className="flex items-center gap-4">
                <button 
                    onClick={onOpenWelcome}
                    className="p-2 bg-[#1a1a1a] hover:bg-[#252525] border border-white/10 rounded-lg text-white transition-colors flex items-center justify-center group"
                    title="Home / Projects"
                >
                    <Home size={18} className="group-hover:text-indigo-400 transition-colors" />
                </button>

                <div className="flex flex-col">
                    <span className="font-bold text-sm text-white tracking-tight">{currentProjectName || "SlideForge"}</span>
                    <div className="flex items-center gap-1.5">
                        {saveStatus === 'saving' && <><Loader2 size={10} className="animate-spin text-indigo-400" /><span className="text-[10px] text-indigo-300">Saving...</span></>}
                        {saveStatus === 'saved' && <><Cloud size={10} className="text-green-400" /><span className="text-[10px] text-green-300">Saved</span></>}
                        {saveStatus === 'error' && <><AlertCircle size={10} className="text-red-400" /><span className="text-[10px] text-red-300">Error</span></>}
                        {saveStatus === 'idle' && <><Cloud size={10} className="text-gray-500" /><span className="text-[10px] text-gray-500">Synced</span></>}
                    </div>
                </div>
            </div>

            {/* Center: Style Controls */}
            <div className="flex items-center gap-3">
                {/* Typography */}
                <div className="relative" ref={typeRef}>
                    <button onClick={() => setIsTypeOpen(!isTypeOpen)} className={`flex items-center gap-2 bg-[#1a1a1a] border border-white/10 px-4 py-2 rounded-md hover:bg-[#252525] transition-colors text-sm font-medium ${isTypeOpen ? 'bg-[#252525] border-white/30' : ''}`}>
                        <Type size={14} className="text-gray-400" />
                        <span className="hidden sm:inline">{TYPOGRAPHY_STYLES.find(t => t.id === currentSlide.typography)?.name || 'Font'}</span>
                        <ChevronDown size={14} className={`text-gray-400 transition-transform ${isTypeOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isTypeOpen && (
                        <div className="absolute top-full right-0 mt-2 w-48 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            {TYPOGRAPHY_STYLES.map(t => (
                                <button key={t.id} onClick={() => { onApplyTypography(t.id); setIsTypeOpen(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-white/5 transition-colors flex items-center justify-between ${currentSlide.typography === t.id ? 'text-indigo-400 font-medium' : 'text-gray-300'}`}>
                                    {t.name} {currentSlide.typography === t.id && <Check size={14} />}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                {/* Theme */}
                <div className="relative" ref={themeRef}>
                    <button onClick={() => setIsThemeOpen(!isThemeOpen)} className={`flex items-center gap-2 bg-[#1a1a1a] border border-white/10 px-4 py-2 rounded-md hover:bg-[#252525] transition-colors text-sm font-medium ${isThemeOpen ? 'bg-[#252525] border-white/30' : ''}`}>
                        <span className="hidden sm:inline">{THEMES.find(t => t.id === currentSlide.theme)?.name || 'Theme'}</span>
                        <ChevronDown size={14} className={`text-gray-400 transition-transform ${isThemeOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isThemeOpen && (
                        <div className="absolute top-full right-0 mt-2 w-48 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            {THEMES.map(t => (
                                <button key={t.id} onClick={() => { onApplyTheme(t.id); setIsThemeOpen(false); }} className={`w-full text-left px-4 py-2 text-sm hover:bg-white/5 transition-colors flex items-center justify-between ${currentSlide.theme === t.id ? 'text-indigo-400 font-medium' : 'text-gray-300'}`}>
                                    {t.name} {currentSlide.theme === t.id && <Check size={14} />}
                                </button>
                            ))}
                        </div>
                    )}
                </div>

                {/* Random */}
                <button onClick={onRandomize} className="flex items-center gap-2 bg-[#1a1a1a] border border-white/10 px-3 py-2 rounded-md hover:bg-[#252525] transition-colors text-sm font-medium text-gray-400 hover:text-white group" title="Randomize Theme & Typography">
                    <Shuffle size={16} className="group-hover:text-indigo-400 transition-colors" />
                    <span className="hidden sm:inline">Random</span>
                </button>
            </div>

            {/* Right: Actions */}
            <div className="flex items-center gap-2">
                {/* Project */}
                <div className="relative" ref={projRef}>
                    <button onClick={() => setIsProjOpen(!isProjOpen)} className={`flex items-center gap-2 px-3 py-2 rounded-md transition-colors text-sm font-medium text-gray-400 hover:text-white hover:bg-white/5 ${isProjOpen ? 'bg-white/5 text-white' : ''}`}>
                        <FolderOpen size={20} /><span className="hidden sm:inline">File</span><ChevronDown size={14} className={`transition-transform ${isProjOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isProjOpen && (
                        <div className="absolute top-full right-0 mt-2 w-56 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            <button onClick={() => { setIsProjOpen(false); setTimeout(onNewProject, 50); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex items-center gap-3 text-gray-200">
                                <FilePlus size={16} className="text-blue-400" /><div className="flex flex-col gap-0.5"><span className="font-medium">New Project</span><span className="text-[10px] text-gray-500">Start fresh (Auto-saved)</span></div>
                            </button>
                            <div className="h-px bg-white/5 mx-2"></div>
                            <button onClick={() => fileInputRef.current?.click()} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex items-center gap-3 text-gray-200">
                                <Upload size={16} className="text-indigo-400" /><div className="flex flex-col gap-0.5"><span className="font-medium">Import JSON</span><span className="text-[10px] text-gray-500">Create new from file</span></div>
                            </button>
                            <div className="h-px bg-white/5 mx-2"></div>
                            <button onClick={() => { onSaveProject(); setIsProjOpen(false); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex items-center gap-3 text-gray-200">
                                <FileDown size={16} className="text-green-400" /><div className="flex flex-col gap-0.5"><span className="font-medium">Download JSON</span><span className="text-[10px] text-gray-500">Save local backup</span></div>
                            </button>
                        </div>
                    )}
                </div>

                {/* Save Cloud */}
                <button onClick={onManualSave} className={`p-2 rounded-md transition-colors relative flex items-center justify-center ${saveStatus === 'error' ? 'text-red-500 hover:bg-red-500/10' : 'text-gray-400 hover:text-white hover:bg-white/5'}`} title="Force Save to Cloud">
                    {saveStatus === 'saving' ? <Loader2 size={20} className="animate-spin" /> : <Cloud size={20} />}
                </button>

                {/* Export */}
                <div className="relative" ref={expRef}>
                    <button onClick={() => setIsExpOpen(!isExpOpen)} className={`flex items-center gap-2 px-3 py-2 rounded-md transition-colors text-sm font-medium ${isExporting ? 'text-indigo-400 bg-indigo-500/10 cursor-not-allowed' : 'text-gray-400 hover:text-white hover:bg-white/5'} ${isExpOpen ? 'bg-white/5 text-white' : ''}`} disabled={isExporting}>
                        <Download size={20} /><span className="hidden sm:inline">Export</span><ChevronDown size={14} className={`transition-transform ${isExpOpen ? 'rotate-180' : ''}`} />
                    </button>
                    {isExpOpen && !isExporting && (
                        <div className="absolute top-full right-0 mt-2 w-48 bg-[#1a1a1a] border border-white/10 rounded-md shadow-xl overflow-hidden z-50 animate-in fade-in zoom-in-95 duration-100">
                            <button onClick={() => { onOpenExport('current'); setIsExpOpen(false); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex flex-col gap-0.5">
                                <span className="text-gray-200 font-medium">Current Slide</span><span className="text-xs text-gray-500">Export this slide only</span>
                            </button>
                            <div className="h-px bg-white/5 mx-2"></div>
                            <button onClick={() => { onOpenExport('all'); setIsExpOpen(false); }} className="w-full text-left px-4 py-3 text-sm hover:bg-white/5 flex flex-col gap-0.5">
                                <span className="text-gray-200 font-medium">All Slides</span><span className="text-xs text-gray-500">Export full presentation</span>
                            </button>
                        </div>
                    )}
                </div>
            </div>
        </header>
    );
};

